const FEED_KEYS = [
  { key: 'latest_meters',    type: 'meter',         topic: 'facis.iot.meters.v1',         protocol: 'kafka', name: 'Smart Meters' },
  { key: 'latest_pv',        type: 'pv',            topic: 'facis.iot.pv.v1',             protocol: 'kafka', name: 'PV Systems' },
  { key: 'latest_weather',   type: 'weather',       topic: 'facis.iot.weather.v1',        protocol: 'kafka', name: 'Weather Stations' },
  { key: 'latest_price',     type: 'price',         topic: 'facis.iot.prices.v1',         protocol: 'kafka', name: 'Energy Price Feed' },
  { key: 'latest_consumers', type: 'load',          topic: 'facis.iot.loads.v1',          protocol: 'kafka', name: 'Consumer Devices' }
];
const now = Date.now();
const sources = [];
for (const f of FEED_KEYS) {
  const arr = global.get(f.key) || [];
  // arr is either an Array or an Object keyed by id; normalise to an array.
  const list = Array.isArray(arr) ? arr : Object.values(arr);
  let lastTs = null;
  for (const item of list) {
    const ts = item && (item.timestamp || item.ts || item.observed_at || null);
    if (ts && (!lastTs || new Date(ts).getTime() > new Date(lastTs).getTime())) lastTs = ts;
  }
  const ageMs = lastTs ? (now - new Date(lastTs).getTime()) : null;
  let status = 'unknown';
  if (lastTs) {
    if (ageMs <= 5 * 60_000) status = 'healthy';
    else if (ageMs <= 30 * 60_000) status = 'degraded';
    else status = 'stale';
  } else if (list.length === 0) {
    status = 'inactive';
  }
  sources.push({
    id: f.key,
    name: f.name,
    type: f.type,
    protocol: f.protocol,
    topic: f.topic,
    entity_count: list.length,
    last_event_ts: lastTs,
    last_event_age_seconds: ageMs ? Math.round(ageMs / 1000) : null,
    status
  });
}
// Static rows for protocols outside the simulation engine.
const engine = global.get('engine') || {};
sources.push({
  id: 'sftp_dsp_drop',
  name: 'DSP SFTP Drop',
  type: 'transfer',
  protocol: 'sftp',
  topic: null,
  entity_count: (global.get('transfers') || []).length || 0,
  last_event_ts: engine.simulation_time || null,
  last_event_age_seconds: null,
  status: 'configured'
});
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.statusCode = 200;
msg.payload = { sources, count: sources.length, engine_state: engine.state || 'unknown' };
return msg;
